1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Step = {
9	  op: string;
10	  items?: Item[];
11	};
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type ScenarioResult = {
19	  results: unknown[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	const CURSED_SURCHARGE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const ITEM_BASE_PREMIUM: Record<string, number> = {
29	  sword: 100,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	const COMPONENT_BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PREMIUM = 60;
37	
38	const groupCountsByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
41	  return counts;
42	};
43	
44	const basePremiumForGroup = (type: string, count: number): number => {
45	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
46	  return count * ITEM_BASE_PREMIUM[type];
47	};
48	
49	const sumBasePremium = (counts: Map<string, number>): number => {
50	  let total = 0;
51	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
52	  return total;
53	};
54	
55	const surchargeForItem = (item: Item): number => {
56	  const base = ITEM_BASE_PREMIUM[item.type];
57	  let surcharge = 0;
58	  if (item.cursed) surcharge += base * CURSED_SURCHARGE;
59	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_SURCHARGE;
60	  return surcharge;
61	};
62	
63	const itemSurcharges = (items: Item[]): number =>
64	  items.reduce((total, item) => total + surchargeForItem(item), 0);
65	
66	const calculatePremium = (items: Item[]): number => {
67	  const base = sumBasePremium(groupCountsByType(items));
68	  const surcharges = itemSurcharges(items);
69	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
70	  return Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE);
71	};
72	
73	export const runScenario = (scenario: Scenario): ScenarioResult => {
74	  const results = scenario.steps.map((step) => ({
75	    premium: calculatePremium(step.items ?? []),
76	  }));
77	  return { results };
78	};
